+       FILE    *f = fopen(indexPath, "r");
        if (f != NULL) {
                QPixmap pixCategory = DBSDGlobal::getIconLoader()->loadIcon("folder",
                                                                                                                                DBSDIconLoader::SmallListItem);
@@ -633,7 +634,7 @@
                lblInfo->setText(tr("%1 Packages available.").arg(count));
        } else {
                /* INDEX couldn't be opened */
